  ('social-worker-moex-00497', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據社會工作師法規定，社會工作師因業務上重大過失行為而移付懲戒程序之敘述，下列何者錯誤？', '["社會工作師移付懲戒事件，由社會工作師懲戒委員會處理之", "社會工作師懲戒委員會應將移付懲戒事件，通知被付懲戒之社會工作師，並限其於通知送達之 翌日起20日內提出答辯或於指定期日到會陳述", "被懲戒人對於社會工作師懲戒委員會之決議有不服者，得於決議書送達之翌日起 20 日內，向 社會工作師懲戒覆審委員會請求覆審", "社會工作師懲戒委員會之委員，應就不具民意代表身分之社會工作、法學專家學者及社會人士 遴聘之，其中法學專家學者及社會人士之比例不得少於二分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
